import React from 'react';

const Heatmap = ({ data }) => {
  const countries = Object.keys(data);
  const categories = ['Entertainment', 'Music', 'News & Politics', 'Comedy', 'Sports', 'Gaming'];

  // Generate simulated heatmap data
  const heatmapData = [];
  countries.forEach(country => {
    categories.forEach(category => {
      const value = (Math.random() * 100 + country.charCodeAt(0) + category.charCodeAt(0)) % 100;
      heatmapData.push({
        country,
        category,
        value
      });
    });
  });

  const maxValue = Math.max(...heatmapData.map(d => d.value));
  const getColor = (value) => {
    const intensity = value / maxValue;
    return `rgba(52, 152, 219, ${intensity})`;
  };

  const cellSize = 60;

  return (
    <div>
      <h2>Country Activity Heatmap</h2>
      <div className="chart-container">
        <div style={{ 
          display: 'flex', 
          flexDirection: 'column', 
          alignItems: 'center',
          padding: '20px',
          paddingTop: '60px'
        }}>
          {/* Category labels */}
          <div style={{ display: 'flex', marginBottom: '10px' }}>
            <div style={{ width: `${cellSize}px` }}></div>
            {categories.map(category => (
              <div 
                key={category}
                style={{ 
                  width: `${cellSize}px`, 
                  textAlign: 'center', 
                  fontSize: '11px',
                  fontWeight: 'bold',
                  padding: '5px',
                  transform: 'rotate(-45deg)',
                  transformOrigin: 'center'
                }}
              >
                {category.length > 10 ? category.substring(0, 10) + '...' : category}
              </div>
            ))}
          </div>

          {/* Heatmap grid */}
          {countries.map(country => (
            <div key={country} style={{ display: 'flex' }}>
              <div style={{ 
                width: `${cellSize}px`, 
                height: `${cellSize}px`,
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                fontWeight: 'bold',
                fontSize: '12px'
              }}>
                {country}
              </div>
              {categories.map(category => {
                const cellData = heatmapData.find(d => d.country === country && d.category === category);
                return (
                  <div
                    key={`${country}-${category}`}
                    style={{
                      width: `${cellSize}px`,
                      height: `${cellSize}px`,
                      backgroundColor: getColor(cellData.value),
                      border: '1px solid white',
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      fontSize: '10px',
                      cursor: 'pointer'
                    }}
                    title={`${country} - ${category}: ${cellData.value.toFixed(1)}`}
                  >
                    {cellData.value.toFixed(0)}
                  </div>
                );
              })}
            </div>
          ))}

          {/* Legend */}
          <div style={{ marginTop: '20px', display: 'flex', alignItems: 'center' }}>
            <span style={{ marginRight: '10px', fontSize: '12px' }}>Low</span>
            <div style={{ 
              width: '200px', 
              height: '20px', 
              background: 'linear-gradient(to right, rgba(52, 152, 219, 0.1), rgba(52, 152, 219, 1))',
              border: '1px solid #ccc'
            }}></div>
            <span style={{ marginLeft: '10px', fontSize: '12px' }}>High</span>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Heatmap;
